import { Component, h, Prop } from '@stencil/core';

@Component({
  tag: 'wdpr-compact-circle-card',
  shadow: true,
})
export class WdprCompactCircleCard {
  @Prop() headline: string;
  @Prop() src: string;
  @Prop({ attribute: 'a11y-alt' }) a11yAlt: string;

  render() {
    return (
      <article class={wrapperClasses}>
        <figure class={mediaWrapperClasses}>
          <wdpr-media src={this.src} alt={this.a11yAlt} aspect="square" objectFit="cover" />
        </figure>

        <span class={headlineClasses}>{this.headline}</span>
      </article>
    );
  }
}

const wrapperClasses = 'flex flex-col items-center gap-150';
const mediaWrapperClasses =
  'w-full aspect-square p-175 md:p-250 bg-surface-default elevation-xsmall-soft rounded-pill overflow-hidden transition-all';
const headlineClasses = 'w-full transition-all text-center text-component-small font-component-default leading-component-small tracking-02 line-clamp-2';
